import{_ as a,o as n,c as t,a2 as s}from"./chunks/framework.CKCxdkvf.js";const b=JSON.parse('{"title":"UXS-001 — Solar System Explorer","description":"","frontmatter":{},"headers":[],"relativePath":"uxs/UXS-001.md","filePath":"uxs/UXS-001.md"}'),o={name:"uxs/UXS-001.md"};function i(l,e,r,c,p,d){return n(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="uxs-001-—-solar-system-explorer" tabindex="-1">UXS-001 — Solar System Explorer <a class="header-anchor" href="#uxs-001-—-solar-system-explorer" aria-label="Permalink to &quot;UXS-001 — Solar System Explorer&quot;">​</a></h1><blockquote><p>Status · Draft v0.1 Visual fidelity · Verified against prototype (P01_solar-system-explorer.html) IA anchor · §surfaces/explore · §topbar-patterns · §shared-tokens Related PRD · PRD-001 Related ADRs · ADR-001 (Three.js r128), ADR-011 (TypeScript), ADR-012 (SvelteKit) Related RFCs · RFC-001 (routing)</p></blockquote><h2 id="why-this-uxs-exists" tabindex="-1">Why this UXS exists <a class="header-anchor" href="#why-this-uxs-exists" aria-label="Permalink to &quot;Why this UXS exists&quot;">​</a></h2><p>The solar system explorer renders to both Three.js (3D mode) and Canvas 2D (2D mode). This UXS defines the static appearance contract for both modes, the detail panel tabs, and the planet-specific visual treatments.</p><h2 id="principles" tabindex="-1">Principles <a class="header-anchor" href="#principles" aria-label="Permalink to &quot;Principles&quot;">​</a></h2><ul><li>The solar system is immediately recognisable — Saturn&#39;s rings, Jupiter&#39;s bands, Earth&#39;s blue</li><li>Selected bodies are unambiguous without obscuring their neighbours</li><li>The TECHNICAL tab shows data, not decoration — Space Mono throughout</li><li>The tooltip appears close to the body without overlapping the label</li><li>2D orbit rings are subtle; planets are the signal</li></ul><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><p>In scope: nav bar, 3D scene layout, 2D canvas layout, planet sphere gradients, selection ring, detail panel (all four tabs), floating tooltip, speed controls, bottom bar. Non-goals: animation timing, hover state transitions, zoom gesture handling. Boundary note: interaction behaviour (click detection logic, zoom formula, drag-to-pan) belongs in the screen module, not here.</p><h2 id="theme" tabindex="-1">Theme <a class="header-anchor" href="#theme" aria-label="Permalink to &quot;Theme&quot;">​</a></h2><p>Dark only. Background <code>#04040c</code> always.</p><h2 id="tokens" tabindex="-1">Tokens <a class="header-anchor" href="#tokens" aria-label="Permalink to &quot;Tokens&quot;">​</a></h2><h3 id="inherited-from-ia" tabindex="-1">Inherited from IA <a class="header-anchor" href="#inherited-from-ia" aria-label="Permalink to &quot;Inherited from IA&quot;">​</a></h3><p>All shared colour tokens, typography tokens, spacing tokens, nav bar spec.</p><h3 id="defined-here" tabindex="-1">Defined here <a class="header-anchor" href="#defined-here" aria-label="Permalink to &quot;Defined here&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>planet-mercury: #c8c8c8 / gradient: #d0c8c0 → #504840</span></span>
<span class="line"><span>planet-venus:   #e8cda0 / gradient: #f0e0a0 → #9a7820</span></span>
<span class="line"><span>planet-earth:   #4b9cd3 / gradient: #6ab8e8 → #0d3050</span></span>
<span class="line"><span>planet-mars:    #c1440e / gradient: #e0704a → #7a2000</span></span>
<span class="line"><span>planet-jupiter: #c88b3a / gradient: #deb878 → #6a3a0e</span></span>
<span class="line"><span>planet-saturn:  #e4d191 / gradient: #ece8b0 → #9a8830</span></span>
<span class="line"><span>planet-uranus:  #7de8e8 / gradient: #a8f0f0 → #207878</span></span>
<span class="line"><span>planet-neptune: #4466bb / gradient: #6080d8 → #101858</span></span>
<span class="line"><span></span></span>
<span class="line"><span>sun-core:       #fff8e7</span></span>
<span class="line"><span>sun-glow-inner: rgba(255,228,130,0.9) at r=0, transparent at r=90px</span></span>
<span class="line"><span>orbit-ring:     rgba(255,255,255,0.05) unselected, rgba(68,102,255,0.3) selected</span></span>
<span class="line"><span>kuiper-belt:    rgba(140,160,210,0.035–0.05) per particle</span></span>
<span class="line"><span>planet-nine:    rgba(160,120,220,0.14) ring, rgba(160,120,220,0.32) label</span></span></code></pre></div><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><h3 id="_3d-mode" tabindex="-1">3D mode <a class="header-anchor" href="#_3d-mode" aria-label="Permalink to &quot;3D mode&quot;">​</a></h3><p>Full viewport Three.js canvas. Nav bar overlaid at top. Planet label divs positioned by 3D projection. Detail panel slides in from right (314px wide). Speed controls and bottom bar at bottom.</p><h3 id="_2d-mode" tabindex="-1">2D mode <a class="header-anchor" href="#_2d-mode" aria-label="Permalink to &quot;2D mode&quot;">​</a></h3><p>Full viewport Canvas 2D. Solar system centre at canvas centre (transform: translate(W/2+panX, H/2+panY) scale(zoom)). Stars drawn in screen space before transform. All orbital objects drawn in world space. Detail panel same as 3D mode.</p><h3 id="detail-panel-tabs" tabindex="-1">Detail panel tabs <a class="header-anchor" href="#detail-panel-tabs" aria-label="Permalink to &quot;Detail panel tabs&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────┐</span></span>
<span class="line"><span>│  PLANET NAME           [×]      │</span></span>
<span class="line"><span>│  Type · Orbital period          │</span></span>
<span class="line"><span>├──────────────────────────────────┤</span></span>
<span class="line"><span>│  OVERVIEW │ TECHNICAL │ LEARN │ SIZES │</span></span>
<span class="line"><span>├──────────────────────────────────┤</span></span>
<span class="line"><span>│  Tab content (scrollable)        │</span></span>
<span class="line"><span>└─────────────────────────────────┘</span></span></code></pre></div><p>Tab strip: 7px Space Mono, letter-spacing 2px. Active tab: white, 2px solid <code>#4466ff</code> bottom border. Inactive: <code>rgba(255,255,255,0.35)</code>.</p><h3 id="bottom-bar" tabindex="-1">Bottom bar <a class="header-anchor" href="#bottom-bar" aria-label="Permalink to &quot;Bottom bar&quot;">​</a></h3><p>Height 68px. Background <code>rgba(4,4,12,0.88)</code>. Speed buttons left. Hint text right.</p><h2 id="component-states" tabindex="-1">Component states <a class="header-anchor" href="#component-states" aria-label="Permalink to &quot;Component states&quot;">​</a></h2><p><strong>Planet (unselected):</strong> base sphere gradient, outer glow at 4–5× radius, label at <code>planet_name_color + cc</code><strong>Planet (selected):</strong> pulsing selection ring (r = planet_radius + 10 + sin(frame)*3), bright label white, panel open <strong>Sun (unselected):</strong> radial glow 0–90px, 14px white core, &quot;SUN&quot; label below <strong>Sun (selected):</strong> same + pulsing gold ring (r = 22 + sin(frame)*4, rgba(255,220,80,0.4–0.7)) <strong>Tooltip (visible):</strong> <code>rgba(4,4,16,0.93)</code> bg, <code>rgba(68,102,255,0.4)</code> border, 3 data lines in Space Mono 7px <strong>Tooltip (hidden):</strong> display:none <strong>Speed button (active):</strong> <code>rgba(68,102,255,0.25)</code> bg, <code>rgba(68,102,255,0.5)</code> border, <code>#7b9cff</code> text <strong>Speed button (inactive):</strong> transparent bg, <code>rgba(255,255,255,0.1)</code> border, <code>rgba(255,255,255,0.35)</code> text</p><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Nav bar: see IA §topbar-patterns, RFC-005</li><li>Detail panel: semantic headings, keyboard-closable (Escape)</li><li>Canvas: <code>aria-label=&quot;Interactive solar system. Use the detail panel for screen reader access.&quot;</code></li><li><code>prefers-reduced-motion</code>: stop auto-orbit in 3D, stop simTime advance in 2D</li></ul><h2 id="acceptance-criteria" tabindex="-1">Acceptance criteria <a class="header-anchor" href="#acceptance-criteria" aria-label="Permalink to &quot;Acceptance criteria&quot;">​</a></h2><ul><li>[ ] All 8 planets visible and correctly coloured in both 3D and 2D</li><li>[ ] Saturn&#39;s rings visible in both modes</li><li>[ ] Jupiter&#39;s bands visible in 2D at size ≥ 6px radius</li><li>[ ] Selection ring pulses on selected planet in both modes</li><li>[ ] Tooltip appears within 200ms of selection in 2D, on hover in 3D</li><li>[ ] Tooltip shows velocity, distance, and orbital params (no planet name)</li><li>[ ] TECHNICAL tab shows vis-viva velocity updating as planet moves</li><li>[ ] SIZES tab canvas shows all planets at true relative scale</li><li>[ ] Sun panel opens with TECHNICAL and LEARN tabs</li><li>[ ] 2D zoom anchored to cursor; 2D drag works</li><li>[ ] All nav links work (MOON, EXPLORE active, PLAN, FLY, MISSIONS, EARTH)</li></ul><hr><h2 id="extension-—-gallery-learn-tabs-v0-1-10" tabindex="-1">Extension — GALLERY + LEARN tabs (v0.1.10) <a class="header-anchor" href="#extension-—-gallery-learn-tabs-v0-1-10" aria-label="Permalink to &quot;Extension — GALLERY + LEARN tabs (v0.1.10)&quot;">​</a></h2><p>PlanetPanel and SunPanel gain two new tabs after the existing OVERVIEW / TECHNICAL / SIZES set. Layout, typography, and tokens follow UXS-004 §Extension and the shared <code>src/lib/styles/panel-tabs.css</code>.</p><h3 id="layout-1" tabindex="-1">Layout <a class="header-anchor" href="#layout-1" aria-label="Permalink to &quot;Layout&quot;">​</a></h3><ul><li>Tabs row stays at top of panel; new tabs appear after SIZES (planets) or TECHNICAL (sun).</li><li>Tab condition: GALLERY shown when <code>static/data/planet-galleries.json[id]</code> (or <code>sun-gallery.json</code>) &gt; 0; LEARN shown when overlay has non-empty <code>links[]</code>.</li></ul><h3 id="tokens-extension" tabindex="-1">Tokens (extension) <a class="header-anchor" href="#tokens-extension" aria-label="Permalink to &quot;Tokens (extension)&quot;">​</a></h3><p><strong>GALLERY thumb (planets, default):</strong> <code>border-color rgba(68, 102, 255, 0.6)</code> on hover (Earth blue accent). <strong>GALLERY thumb (sun):</strong> <code>border-color rgba(255, 200, 80, 0.6)</code> on hover (theme-gold override; scoped CSS in SunPanel). <strong>Active tab border (planets):</strong> <code>#4466ff</code>. <strong>Active tab border (sun):</strong> <code>#ffc850</code>.</p><h3 id="acceptance-criteria-extension" tabindex="-1">Acceptance criteria (extension) <a class="header-anchor" href="#acceptance-criteria-extension" aria-label="Permalink to &quot;Acceptance criteria (extension)&quot;">​</a></h3><ul><li>[ ] GALLERY tab renders when planet/sun manifest count &gt; 0; hidden otherwise</li><li>[ ] LEARN tab renders when overlay has links; hidden otherwise</li><li>[ ] Lightbox opens on thumbnail click; closes on click anywhere</li><li>[ ] LEARN tab shows tiered intro/core/deep groupings with the canonical accent colors (teal/blue/gold)</li></ul>`,40)])])}const u=a(o,[["render",i]]);export{b as __pageData,u as default};
